153	        ...existing,
154	        [provider]: "That custom model is already saved.",
155	      }));
156	      return;
157	    }
158	
159	    updateSettings(patchCustomModels(provider, [...customModels, normalized]));
160	    setCustomModelInputByProvider((existing) => ({
161	      ...existing,
162	      [provider]: "",
163	    }));
164	    setCustomModelErrorByProvider((existing) => ({
165	      ...existing,
166	      [provider]: null,
167	    }));
