/**
 * T3 Code built-in theme definitions.
 *
 * Each theme maps to a set of CSS custom-property values applied to the
 * document root via `data-theme="<id>"`.  The `isDark` flag controls whether
 * the `.dark` Tailwind variant is also activated.
 */

/** Unique identifiers for every built-in theme. */
export type AppThemeId = "t3-light" | "t3-dark" | "t3-midnight";

/** Theme preference stored in local storage — a concrete theme or "system". */
export type ThemePreference = AppThemeId | "system";

/**
 * Semantic colour slots required by every theme.
 * Values must be valid CSS colour strings.
 */
export type AppThemeColors = {
  /** Main app canvas background. */
  background: string;
  /** Primary text colour on the main canvas. */
  foreground: string;
  /** Brand / interactive accent (buttons, focus rings, active states). */
  accent: string;
  /** Sidebar / navigation panel background. */
  sidebar: string;
  /** Sidebar foreground (icons, text). */
  sidebarForeground: string;
  /** Code-editor pane background. */
  editor: string;
  /** Integrated terminal background. */
  terminal: string;
  /** Status-bar strip background. */
  statusBar: string;
  /** Status-bar strip foreground. */
  statusBarForeground: string;
  /** Elevated card / panel surface. */
  card: string;
  /** Default separator / border colour. */
  border: string;
  /** Subdued surface (muted backgrounds). */
  muted: string;
  /** Subdued text colour. */
  mutedForeground: string;
  /** Primary interactive action colour. */
  primary: string;
};

/** Full description of a T3 Code theme. */
export type AppTheme = {
  readonly id: AppThemeId;
  /** Human-readable name shown in the theme picker. */
  readonly name: string;
  /** True when the theme uses a dark colour palette. */
  readonly isDark: boolean;
  readonly colors: AppThemeColors;
};

/** All built-in themes in display order. */
export const BUILT_IN_THEMES: ReadonlyArray<AppTheme> = [
  {
    id: "t3-light",
    name: "T3 Light",
    isDark: false,
    colors: {
      background: "#ffffff",
      foreground: "#262626",
      accent: "oklch(0.488 0.217 264)",
      sidebar: "#f5f5f5",
      sidebarForeground: "#525252",
      editor: "#ffffff",
      terminal: "#fafafa",
      statusBar: "#e5e5e5",
      statusBarForeground: "#525252",
      card: "#ffffff",
      border: "rgba(0,0,0,0.08)",
      muted: "rgba(0,0,0,0.04)",
      mutedForeground: "#737373",
      primary: "oklch(0.488 0.217 264)",
    },
  },
  {
    id: "t3-dark",
    name: "T3 Dark",
    isDark: true,
    colors: {
      background: "#0f0f0f",
      foreground: "#f5f5f5",
      accent: "oklch(0.588 0.217 264)",
      sidebar: "#161616",
      sidebarForeground: "#a3a3a3",
      editor: "#111111",
      terminal: "#0d0d0d",
      statusBar: "#1c1c1c",
      statusBarForeground: "#a3a3a3",
      card: "#141414",
      border: "rgba(255,255,255,0.06)",
      muted: "rgba(255,255,255,0.04)",
      mutedForeground: "#737373",
      primary: "oklch(0.588 0.217 264)",
    },
  },
  {
    id: "t3-midnight",
    name: "T3 Midnight",
    isDark: true,
    colors: {
      background: "#000000",
      foreground: "#e5e5e5",
      accent: "oklch(0.65 0.24 264)",
      sidebar: "#080808",
      sidebarForeground: "#8a8a8a",
      editor: "#000000",
      terminal: "#030303",
      statusBar: "#0d0d0d",
      statusBarForeground: "#8a8a8a",
      card: "#0a0a0a",
      border: "rgba(255,255,255,0.05)",
      muted: "rgba(255,255,255,0.03)",
      mutedForeground: "#666666",
      primary: "oklch(0.65 0.24 264)",
    },
  },
] satisfies ReadonlyArray<AppTheme>;

/** The theme applied when no preference has been persisted. */
export const DEFAULT_THEME_ID: AppThemeId = "t3-dark";

/** Return a built-in theme by ID, falling back to the default. */
export function getThemeById(id: AppThemeId): AppTheme {
  for (const theme of BUILT_IN_THEMES) {
    if (theme.id === id) return theme;
  }
  // Unreachable for valid AppThemeId values; fall back defensively.
  const fallback = BUILT_IN_THEMES.find((t) => t.id === DEFAULT_THEME_ID);
  if (fallback) return fallback;
  throw new Error(`Theme "${id}" not found and no fallback available.`);
}

