import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  type AppThemeId,
  type ThemePreference,
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  getThemeById,
} from "@t3tools/shared/theme";

export type { AppThemeId, ThemePreference };

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: { preference: ThemePreference; systemDark: boolean } | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/** Read the stored preference, migrating legacy "light"/"dark" values. */
function getStored(): ThemePreference {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "system") return "system";
  // Migrate pre-theme-system values.
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  // Validate against known theme IDs.
  if (BUILT_IN_THEMES.some((t) => t.id === raw)) return raw as AppThemeId;
  return "system";
}

/** Resolve a stored preference to a concrete theme ID. */
function resolveThemeId(preference: ThemePreference): AppThemeId {
  if (preference !== "system") return preference;
  return getSystemDark() ? DEFAULT_THEME_ID : "t3-light";
}

function applyTheme(preference: ThemePreference, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const resolvedId = resolveThemeId(preference);
  const theme = getThemeById(resolvedId);

  // Set data-theme attribute — CSS variable blocks key off this.
  document.documentElement.setAttribute("data-theme", resolvedId);
  // Toggle .dark for Tailwind dark-mode utilities.
  document.documentElement.classList.toggle("dark", theme.isDark);

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash.
applyTheme(getStored());

function getSnapshot() {
  const preference = getStored();
  const systemDark = preference === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.preference === preference &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { preference, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const { preference } = snapshot;

  const resolvedThemeId = resolveThemeId(preference);
  const resolvedTheme: "light" | "dark" = getThemeById(resolvedThemeId).isDark ? "dark" : "light";

  const setTheme = useCallback((next: ThemePreference) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep the DOM in sync on mount / preference change.
  useEffect(() => {
    applyTheme(preference);
  }, [preference]);

  return {
    /** The raw stored preference — a concrete theme ID or "system". */
    themePreference: preference,
    /** The concrete theme ID currently applied to the document. */
    resolvedThemeId,
    /**
     * "light" or "dark" — stable for all existing consumers that key off
     * light/dark polarity (diff rendering, syntax highlighting, etc.).
     */
    resolvedTheme,
    setTheme,
  } as const;
}

