/* ─────────────────────────────────────────────────────────────────────────
   Named theme overrides
   These `:root[data-theme="..."]` blocks (specificity 0,1,1) override both
   the `:root` light defaults and the dark @variant block, so they always
   reflect the explicitly chosen palette regardless of OS preference.
   ───────────────────────────────────────────────────────────────────────── */

:root[data-theme="t3-light"] {
  color-scheme: light;
  --background: #ffffff;
  --foreground: #262626;
  --card: #ffffff;
  --card-foreground: #262626;
