  --secondary: rgba(0, 0, 0, 0.04);
  --secondary-foreground: #262626;
  --muted: rgba(0, 0, 0, 0.04);
  --muted-foreground: #737373;
  --accent: rgba(0, 0, 0, 0.04);
  --accent-foreground: #262626;
  --destructive: #ef4444;
  --destructive-foreground: #b91c1c;
  --border: rgba(0, 0, 0, 0.08);
  --input: rgba(0, 0, 0, 0.1);
  --ring: oklch(0.488 0.217 264);
  --info: #3b82f6;
  --info-foreground: #1d4ed8;
  --success: #10b981;
  --success-foreground: #047857;
  --warning: #f59e0b;
  --warning-foreground: #b45309;
  --sidebar: #f5f5f5;
  --sidebar-foreground: #525252;
  --editor: #ffffff;
  --terminal: #fafafa;
  --status-bar: #e5e5e5;
  --status-bar-foreground: #525252;
}

:root[data-theme="t3-dark"] {
  color-scheme: dark;
  --background: #0f0f0f;
  --foreground: #f5f5f5;
  --card: #141414;
  --card-foreground: #f5f5f5;
  --popover: #141414;
  --popover-foreground: #f5f5f5;
  --primary: oklch(0.588 0.217 264);
