  --info-foreground: #93c5fd;
  --success: #34d399;
  --success-foreground: #6ee7b7;
  --warning: #fbbf24;
  --warning-foreground: #fcd34d;
  --sidebar: #161616;
  --sidebar-foreground: #a3a3a3;
  --editor: #111111;
  --terminal: #0d0d0d;
  --status-bar: #1c1c1c;
  --status-bar-foreground: #a3a3a3;
}

:root[data-theme="t3-midnight"] {
  color-scheme: dark;
  --background: #000000;
  --foreground: #e5e5e5;
  --card: #0a0a0a;
  --card-foreground: #e5e5e5;
  --popover: #0a0a0a;
  --popover-foreground: #e5e5e5;
