import { BUILT_IN_THEMES } from "@t3tools/shared/theme";
import type { AppTheme, ThemePreference } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";

// ─── Swatch preview ──────────────────────────────────────────────────────────

type ThemeSwatchProps = {
  theme: AppTheme;
  selected: boolean;
  onClick: () => void;
};

function ThemeSwatch({ theme, selected, onClick }: ThemeSwatchProps) {
  const { colors } = theme;
  return (
    <button
      type="button"
      onClick={onClick}
      aria-pressed={selected}
      aria-label={`Select ${theme.name} theme`}
      className={`group relative flex flex-col overflow-hidden rounded-xl border transition-all focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background ${
        selected
          ? "border-primary/60 ring-2 ring-primary/30"
          : "border-border hover:border-border/80"
      }`}
      style={{ background: colors.background }}
    >
      {/* Mini app layout preview */}
      <div className="flex h-16 w-full overflow-hidden" aria-hidden="true">
        {/* Sidebar strip */}
        <div
          className="flex w-8 shrink-0 flex-col gap-1 p-1.5"
          style={{ background: colors.sidebar }}
        >
          {/* Sidebar item dots */}
          <div
            className="h-1.5 w-full rounded-full opacity-40"
            style={{ background: colors.sidebarForeground }}
          />
          <div
            className="h-1.5 w-4/5 rounded-full opacity-30"
            style={{ background: colors.sidebarForeground }}
          />
          <div
            className="h-1.5 w-full rounded-full opacity-25"
            style={{ background: colors.sidebarForeground }}
          />
          <div
            className="mt-auto h-1.5 w-3/5 rounded-full opacity-20"
            style={{ background: colors.sidebarForeground }}
          />
        </div>

        {/* Main content area */}
        <div
          className="flex flex-1 flex-col gap-1 p-1.5"
          style={{ background: colors.editor }}
        >
          {/* Fake toolbar */}
          <div className="flex items-center gap-1">
            <div
              className="h-1.5 w-12 rounded-full opacity-40"
              style={{ background: colors.foreground }}
            />
            <div className="flex-1" />
            <div
              className="h-3 w-8 rounded opacity-90"
              style={{ background: colors.accent }}
            />
          </div>
          {/* Fake content lines */}
          <div
            className="h-1 w-4/5 rounded-full opacity-20"
            style={{ background: colors.foreground }}
          />
          <div
            className="h-1 w-3/5 rounded-full opacity-15"
            style={{ background: colors.foreground }}
          />
          <div
            className="h-1 w-full rounded-full opacity-10"
            style={{ background: colors.foreground }}
          />
          {/* Status bar */}
          <div
            className="mt-auto flex h-3 items-center gap-0.5 rounded px-1"
            style={{ background: colors.statusBar }}
          >
            <div
              className="h-1 w-6 rounded-full opacity-50"
              style={{ background: colors.statusBarForeground }}
            />
            <div
              className="h-1 w-4 rounded-full opacity-30"
              style={{ background: colors.statusBarForeground }}
            />
          </div>
        </div>
      </div>

      {/* Colour swatch strip */}
      <div className="flex h-2 w-full" aria-hidden="true">
        <div className="flex-1" style={{ background: colors.background }} />
        <div className="flex-1" style={{ background: colors.sidebar }} />
        <div className="flex-1" style={{ background: colors.editor }} />
        <div className="flex-1" style={{ background: colors.accent }} />
        <div className="flex-1" style={{ background: colors.statusBar }} />
      </div>

      {/* Label row */}
      <div
        className="flex items-center justify-between px-2.5 py-2"
        style={{ background: colors.card, borderTop: `1px solid ${colors.border}` }}
      >
        <span
          className="text-xs font-medium"
          style={{ color: colors.foreground }}
        >
          {theme.name}
        </span>
        {selected && (
          <span
            className="rounded px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wide"
            style={{
              background: colors.accent,
              color: "#ffffff",
              opacity: 0.9,
            }}
          >
            On
          </span>
        )}
      </div>
    </button>
  );
}

// ─── System option ────────────────────────────────────────────────────────────

type SystemOptionProps = {
  selected: boolean;
  onClick: () => void;
};

function SystemOption({ selected, onClick }: SystemOptionProps) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      onClick={onClick}
      className={`flex w-full items-center justify-between rounded-lg border px-3 py-2.5 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
    >
      <span className="flex flex-col gap-0.5">
        <span className="text-sm font-medium">System</span>
        <span className="text-xs text-muted-foreground">
          Follows your OS appearance setting.
        </span>
      </span>
      {selected && (
        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wide text-primary">
          Active
        </span>
      )}
    </button>
  );
}

// ─── Public component ─────────────────────────────────────────────────────────

/**
 * Theme selector with colour-swatch previews for each built-in theme and a
 * "System" option that follows the OS appearance setting.
 */
export function ThemeSelector() {
  const { themePreference, resolvedThemeId, setTheme } = useTheme();

  return (
    <div className="space-y-3">
      {/* Named theme swatches */}
      <div className="grid grid-cols-3 gap-3">
        {BUILT_IN_THEMES.map((theme) => (
          <ThemeSwatch
            key={theme.id}
            theme={theme}
            selected={themePreference === theme.id}
            onClick={() => setTheme(theme.id)}
          />
        ))}
      </div>

      {/* System option */}
      <SystemOption
        selected={themePreference === "system"}
        onClick={() => setTheme("system")}
      />

      <p className="text-xs text-muted-foreground">
        Active palette:{" "}
        <span className="font-medium text-foreground">{resolvedThemeId}</span>
      </p>
    </div>
  );
}

